import xml.etree.ElementTree as ET
import csv

def task_func(xml_content, output_csv_path):
    try:
        root = ET.fromstring(xml_content)
    except ET.ParseError as e:
        raise ET.ParseError(f"Failed to parse XML: {e}")

    try:
        with open(output_csv_path, 'w', newline='', encoding='utf-8') as csvfile:
            if len(root) == 0:
                return

            # Collect all unique field names from attributes and text content
            fieldnames = set()
            rows = []

            def extract_elements(element):
                row = {}
                # Add attributes
                for key, value in element.attrib.items():
                    row[key] = value
                # Add text content
                if element.text and element.text.strip():
                    row['text'] = element.text.strip()
                # Recursively process children
                for child in element:
                    child_text = child.text.strip() if child.text else ''
                    child_key = child.tag
                    if child_key in row:
                        # Handle duplicate keys by appending
                        row[child_key] = f"{row[child_key]},{child_text}"
                    else:
                        row[child_key] = child_text
                    extract_elements(child)
                rows.append(row)

            for elem in root:
                extract_elements(elem)

            # Collect all unique fieldnames
            for row in rows:
                fieldnames.update(row.keys())
            fieldnames = sorted(fieldnames)

            writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
            writer.writeheader()
            for row in rows:
                writer.writerow({key: row.get(key, '') for key in fieldnames})
    except IOError as e:
        raise IOError(f"Failed to write to CSV file: {e}")
